// Hist贸rico longo para CRM
// Usa apenas Merge2
// Pega 煤ltimas mensagens 煤teis
// Corrige speaker de transcri莽茫o interna de 谩udio
// Evita duplicar 谩udio nulo + transcri莽茫o
// Sa铆da 煤nica

const LIMIT = $input.first().json.qtd_historico || 30;
const OUTGOING_NAME = $('CW_account_id').first().json.nome_agente;

// Pega todos os itens do Merge2
const inputItems = $input.all();

function normalizeContent(text) {
  return String(text || '')
    .replace(/\r/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function isInternalAudioTranscript(msg) {
  const content = String(msg.content || '');
  return content.startsWith('[TRANSCRI脟脙O INTERNA DO 脕UDIO');
}

function isInternalformEntry(msg) {
  const content = String(msg.content || '');
  return content.startsWith('[CHEGOU NOVO LEAD FORMUL脕RIO]');
}

function extractReferencedMessageId(msg) {
  const inReplyTo = msg?.content_attributes?.in_reply_to;
  if (inReplyTo) return Number(inReplyTo);

  const content = String(msg.content || '');
  const match = content.match(/msg_id\s+(\d+)/i);
  return match ? Number(match[1]) : null;
}

function getSpeakerFromType(messageType) {
  const type = Number(messageType);
  if (type === 0) return 'Lead';
  if (type === 1) return OUTGOING_NAME;
  return 'Sistema';
}

function getSpeaker(msg, messageMap) {
  if (isInternalAudioTranscript(msg)) {
    const referencedId = extractReferencedMessageId(msg);
    const originalMsg = referencedId ? messageMap.get(referencedId) : null;

    if (originalMsg) {
      return getSpeakerFromType(originalMsg.message_type);
    }
  }

  return getSpeakerFromType(msg.message_type);
}

function cleanTranscriptContent(text) {
  const content = String(text || '');

  if (!content.startsWith('[TRANSCRI脟脙O INTERNA DO 脕UDIO')) {
    return normalizeContent(content);
  }

  return normalizeContent(
    content
      .replace(/^\[TRANSCRI脟脙O INTERNA DO 脕UDIO[^\n]*\]\n?/i, '')
      .replace(/^猬囷笍Transcri莽茫o do 谩udio猬囷笍[^\n]*\n?/i, '')
  );
}

// 1. Extrair mensagens
const rawMessages = inputItems
  .map(item => item.json)
  .filter(j => j && typeof j === 'object' && j.id);

// 2. Remover duplicados por id
const uniqueMap = new Map();
for (const msg of rawMessages) {
  uniqueMap.set(Number(msg.id), msg);
}

let messages = Array.from(uniqueMap.values());

// 3. Ordenar por id crescente primeiro
messages.sort((a, b) => Number(a.id) - Number(b.id));

// 4. Criar mapa completo por id
const messageMap = new Map();
for (const msg of messages) {
  messageMap.set(Number(msg.id), msg);
}

// 5. Descobrir quais mensagens de 谩udio possuem transcri莽茫o interna
const transcribedOriginalIds = new Set();

for (const msg of messages) {
  if (isInternalAudioTranscript(msg)) {
    const referencedId = extractReferencedMessageId(msg);
    if (referencedId) {
      transcribedOriginalIds.add(referencedId);
    }
  }
}

// 6. Filtrar mensagens 煤teis
messages = messages.filter(msg => {
  const type = Number(msg.message_type);

  // S贸 mant茅m type 0 e 1
  if (!(type === 0 || type === 1)) return false;

  // Remove mensagens privadas, exceto transcri莽茫o interna
  if (msg.private === true && !isInternalAudioTranscript(msg)) return false;

  // Remove o 谩udio original sem conte煤do quando j谩 existe transcri莽茫o
  const hasEmptyContent = !normalizeContent(msg.content);
  if (hasEmptyContent && transcribedOriginalIds.has(Number(msg.id))) return false;

  // Remove mensagens vazias comuns
  if (hasEmptyContent && !isInternalAudioTranscript(msg)) return false;

  return true;
});

// 7. Pegar s贸 as 煤ltimas N
const lastMessages = messages.slice(-LIMIT);

// 8. Montar texto pro CRM
const historyText = lastMessages
  .map(msg => {
    const speaker = getSpeaker(msg, messageMap);
    const content = cleanTranscriptContent(msg.content);

    return `${speaker}: ${content}`;
  })
  .join('\n');

// 9. Sa铆da 煤nica
return [
  {
    json: {
      messages_total_received: rawMessages.length,
      messages_total_unique: uniqueMap.size,
      messages_total_filtered: messages.length,
      messages_sent_to_crm: lastMessages.length,
      first_message_id: lastMessages.length ? lastMessages[0].id : null,
      last_message_id: lastMessages.length ? lastMessages[lastMessages.length - 1].id : null,
      history_for_crm: historyText,
      messages_for_crm: lastMessages
    }
  }
];

const item = $input.first().json || {};

const messages = Array.isArray(item?.messages_for_crm)
  ? item.messages_for_crm
  : [];

// ==================================================
// HELPERS
// ==================================================

function clean(value, preserveNewLines = false) {
  let text = String(value || '')
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');

  if (preserveNewLines) {
    text = text
      .split('\n')
      .map(line => line.replace(/[ \t]+/g, ' ').trim())
      .filter(Boolean)
      .join('\n')
      .trim();
  } else {
    text = text
      .replace(/\s+/g, ' ')
      .trim();
  }

  return text;
}

function norm(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toNumberOrNull(value) {
  if (value === undefined || value === null || String(value).trim() === '') return null;
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

function isLeadMessage(msg) {
  return Number(msg?.message_type) === 0;
}

function isOutgoingMessage(msg) {
  return Number(msg?.message_type) === 1;
}

function isPrivate(msg) {
  return msg?.private === true;
}

function senderName(msg) {
  return clean(
    msg?.sender?.name ||
    msg?.sender?.available_name ||
    ''
  );
}

function senderType(msg) {
  return clean(
    msg?.sender?.type ||
    msg?.sender_type ||
    ''
  ).toLowerCase();
}

function isHumanFlavia(msg) {
  const name = norm(senderName(msg));

  return (
    name.includes('flavia') ||
    name.includes('flavia atendimento') ||
    name.includes('atendimento auau')
  );
}

function isInternalAudioTranscription(msg) {
  const content = String(msg?.content || '');

  return (
    isPrivate(msg) &&
    isOutgoingMessage(msg) &&
    /\[TRANSCRI脟脙O INTERNA DO 脕UDIO/i.test(content)
  );
}

function extractAudioOriginalMessageId(msg) {
  const content = String(msg?.content || '');

  const fromText = content.match(/msg_id\s+(\d+)/i);
  if (fromText?.[1]) return Number(fromText[1]);

  const fromReply = toNumberOrNull(msg?.content_attributes?.in_reply_to);
  if (fromReply) return fromReply;

  return toNumberOrNull(msg?.id);
}

function extractAudioTranscriptionText(msg) {
  let text = String(msg?.content || '');

  text = text
    .replace(/\[TRANSCRI脟脙O INTERNA DO 脕UDIO[^\]]*\]/gi, '')
    .replace(/猬囷笍\s*Transcri莽茫o do 谩udio\s*猬囷笍[^\n]*/gi, '')
    .replace(/- aproximadamente [^\n]*/gi, '');

  return clean(text, true);
}

function getAttachments(msg) {
  if (Array.isArray(msg?.attachments)) return msg.attachments;
  if (Array.isArray(msg?.files)) return msg.files;
  return [];
}

function getFirstAttachmentUrl(msg) {
  const attachments = getAttachments(msg);
  const first = attachments[0] || {};

  return clean(
    first?.data_url ||
    first?.download_url ||
    first?.file_url ||
    first?.url ||
    first?.thumb_url ||
    ''
  );
}

function getMessageModality(msg, text) {
  const attachments = getAttachments(msg);
  const hasText = Boolean(clean(text));
  const hasAttachment = attachments.length > 0;

  if (!hasAttachment) return 'text_only';

  const first = attachments[0] || {};
  const fileType = String(
    first?.file_type ||
    first?.type ||
    first?.content_type ||
    first?.mime_type ||
    ''
  ).toLowerCase();

  let mediaType = 'attachment';

  if (fileType.includes('image')) mediaType = 'image';
  else if (fileType.includes('pdf')) mediaType = 'document';
  else if (fileType.includes('document')) mediaType = 'document';
  else if (fileType.includes('application')) mediaType = 'document';
  else if (fileType.includes('audio')) mediaType = 'audio';
  else if (fileType.includes('video')) mediaType = 'video';
  else if (fileType.includes('file')) mediaType = 'document';

  return hasText ? `${mediaType}_with_text` : `${mediaType}_only`;
}

function isRelevantText(text) {
  const t = clean(text);

  if (!t) return false;

  // Remove s贸 ru铆do puro.
  // Mant茅m "sim", "n茫o", "pode", porque isso muda estado.
  if (/^(ok|obrigado|obrigada|obg|valeu|馃憤|馃憣|馃檹|鉂わ笍|鉂kkk|rs|rsrs)$/i.test(t)) {
    return false;
  }

  return true;
}

function roleFromMessage(msg) {
  if (msg.__is_audio_transcription === true) return 'lead';

  if (isLeadMessage(msg)) return 'lead';

  if (isOutgoingMessage(msg)) {
    if (isHumanFlavia(msg)) return 'humano';
    return 'bruna';
  }

  return 'sistema';
}

function historyLabel(role) {
  if (role === 'lead') return 'Lead';
  if (role === 'humano') return 'Humano AuAu';
  if (role === 'bruna') return 'Bruna Auau';
  return 'Sistema';
}

function normalizeMessage(msg) {
  const isAudioTranscription = isInternalAudioTranscription(msg);

  const id = isAudioTranscription
    ? extractAudioOriginalMessageId(msg)
    : toNumberOrNull(msg?.id);

  const content = isAudioTranscription
    ? extractAudioTranscriptionText(msg)
    : clean(msg?.content || '', true);

  const role = isAudioTranscription
    ? 'lead'
    : roleFromMessage(msg);

  const messageType = role === 'lead' ? 0 : 1;

  const attachments = getAttachments(msg);
  const hasText = Boolean(clean(content));
  const hasAttachment = attachments.length > 0;

  return {
    id,
    content,
    inbox_id: msg?.inbox_id ?? item?.chatwoot?.inbox_id ?? null,
    conversation_id: msg?.conversation_id ?? item?.chatwoot?.conversation_id ?? null,
    message_type: messageType,
    content_type: msg?.content_type || 'text',
    status: msg?.status || '',
    content_attributes: msg?.content_attributes || {},
    created_at: msg?.created_at ?? null,
    private: false,
    source_id:
      msg?.source_id ||
      msg?.content_attributes?.in_reply_to_external_id ||
      null,
    sender_type: role === 'lead' ? 'contact' : 'user',
    sender_name: senderName(msg),
    sender_original_type: senderType(msg),
    role,
    role_label: historyLabel(role),
    has_text: hasText,
    has_attachment: hasAttachment,
    attachments,
    data_url: getFirstAttachmentUrl(msg) || null,
    message_modality: getMessageModality(msg, content),
    is_audio_transcription: isAudioTranscription,
    transcription_note_id: isAudioTranscription ? toNumberOrNull(msg?.id) : null,
    original_message_type: msg?.message_type,
    original_private: msg?.private === true
  };
}

// ==================================================
// NORMALIZA MESSAGES_FOR_CRM EM CHATWOOT_MESSAGES
// ==================================================

let chatwootMessages = messages
  .map(normalizeMessage)
  .filter(msg => msg.id !== null && msg.id !== undefined)
  .filter(msg => isRelevantText(msg.content) || msg.has_attachment)
  .sort((a, b) => Number(a.id) - Number(b.id));

// Dedup por ID, mantendo o 煤ltimo item calculado.
const byId = new Map();

for (const msg of chatwootMessages) {
  byId.set(Number(msg.id), msg);
}

chatwootMessages = Array.from(byId.values())
  .sort((a, b) => Number(a.id) - Number(b.id));

const chatwootLeadMessages = chatwootMessages.filter(msg => msg.role === 'lead');
const chatwootBrunaMessages = chatwootMessages.filter(msg => msg.role === 'bruna');
const chatwootHumanMessages = chatwootMessages.filter(msg => msg.role === 'humano');

// ==================================================
// 脷LTIMAS MENSAGENS RELEVANTES
// ==================================================

const lastLeadMessage = chatwootLeadMessages.length
  ? clean(chatwootLeadMessages[chatwootLeadMessages.length - 1].content, true)
  : clean(item?.last_lead_message || item?.inputs?.mensagem_ultima_lead || '', true);

const lastBrunaMessage = chatwootBrunaMessages.length
  ? clean(chatwootBrunaMessages[chatwootBrunaMessages.length - 1].content, true)
  : clean(item?.last_bruna_message || item?.inputs?.mensagem_ultima_bruna || '', true);

const lastHumanMessage = chatwootHumanMessages.length
  ? clean(chatwootHumanMessages[chatwootHumanMessages.length - 1].content, true)
  : '';

// ==================================================
// HISTORY_FOR_CRM LIMPO
// ==================================================

const historyLines = chatwootMessages
  .map(msg => {
    const text = clean(msg.content, true);
    if (!text) return '';

    return `${msg.role_label}: ${text}`;
  })
  .filter(Boolean);

const historyForCrm = historyLines.join('\n');

// ==================================================
// ATUALIZA ITEM
// ==================================================

item.chatwoot_messages = chatwootMessages;
item.chatwoot_messages_lead = chatwootLeadMessages;
item.chatwoot_messages_bruna = chatwootBrunaMessages;
item.chatwoot_messages_humano = chatwootHumanMessages;

item.last_lead_message = lastLeadMessage;
item.last_bruna_message = lastBrunaMessage;
item.last_human_message = lastHumanMessage;

item.history_for_crm = historyForCrm || clean(item?.history_for_crm || '', true);

item.messages_total_received = messages.length;
item.messages_total_unique = chatwootMessages.length;
item.messages_total_filtered = chatwootMessages.length;
item.messages_sent_to_crm = chatwootMessages.length;

item.first_message_id = chatwootMessages.length
  ? chatwootMessages[0].id
  : null;

item.last_message_id = chatwootMessages.length
  ? chatwootMessages[chatwootMessages.length - 1].id
  : null;

item.relevant_message_debug = {
  generated_chatwoot_messages: true,
  total_raw_messages: messages.length,
  total_normalized_messages: chatwootMessages.length,
  total_lead_messages: chatwootLeadMessages.length,
  total_bruna_messages: chatwootBrunaMessages.length,
  total_human_messages: chatwootHumanMessages.length,
  audio_transcriptions_converted_to_lead: chatwootMessages.filter(m => m.is_audio_transcription).length,
  first_message_id: item.first_message_id,
  last_message_id: item.last_message_id
};

return [{ json: item }];

const item = $input.first().json || {};

const out = item?.output && typeof item.output === 'object' ? { ...item.output } : {};

// ==================================================
// HELPERS
// ==================================================

function pick(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

function clean(value, preserveNewLines = false) {
  let text = String(value || '')
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n');

  if (preserveNewLines) {
    return text
      .split('\n')
      .map(line => line.replace(/[ \t]+/g, ' ').trim())
      .filter(Boolean)
      .join('\n')
      .trim();
  }

  return text.replace(/\s+/g, ' ').trim();
}

function norm(value) {
  return clean(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function bool(v) {
  return v === true || ['true', '1', 'sim', 'yes'].includes(norm(v));
}

function appendObs(...parts) {
  return parts
    .map(p => clean(p, true))
    .filter(Boolean)
    .join(' ')
    .trim();
}

function toNumberOrNull(value) {
  if (value === undefined || value === null || String(value).trim() === '') return null;
  const n = Number(String(value).replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

function parseAgeYears(ageValue, ageText) {
  const direct = toNumberOrNull(ageValue);
  if (direct !== null) return direct;

  const text = norm(ageText);
  if (!text) return null;

  const yearMatch = text.match(/(\d+(?:[.,]\d+)?)\s*ano/);
  if (yearMatch) return toNumberOrNull(yearMatch[1]);

  const monthMatch = text.match(/(\d+(?:[.,]\d+)?)\s*m[e锚]s/);
  if (monthMatch) {
    const months = toNumberOrNull(monthMatch[1]);
    return months === null ? null : months / 12;
  }

  return null;
}

function isFalseLike(value) {
  const text = norm(value);

  if (value === false) return true;
  if (['false', '0', 'nao', 'n茫o', 'no'].includes(text)) return true;

  return (
    /\bnao\b/.test(text) ||
    /\bnao castrad[oa]\b/.test(text) ||
    /\bnao e castrad[oa]\b/.test(text) ||
    /\bnao esta castrad[oa]\b/.test(text)
  );
}

function getMessages() {
  if (Array.isArray(item.chatwoot_messages)) return item.chatwoot_messages;
  if (Array.isArray(item.messages_for_crm)) return item.messages_for_crm;
  return [];
}

function getLastLeadMessage() {
  const messages = getMessages();
  const leadMessages = messages
    .filter(m => m.role === 'lead' || Number(m.message_type) === 0)
    .filter(m => clean(m.content, true));

  if (leadMessages.length) {
    return clean(leadMessages[leadMessages.length - 1].content, true);
  }

  return clean(
    pick(
      item.last_lead_message,
      item.inputs?.mensagem_ultima_lead,
      item.message?.content,
      ''
    ),
    true
  );
}

function getLastBrunaMessage() {
  const messages = getMessages();
  const brunaMessages = messages
    .filter(m => m.role === 'bruna' || Number(m.message_type) === 1)
    .filter(m => !m.private)
    .filter(m => clean(m.content, true));

  if (brunaMessages.length) {
    return clean(brunaMessages[brunaMessages.length - 1].content, true);
  }

  return clean(
    pick(
      item.last_bruna_message,
      item.inputs?.mensagem_ultima_bruna,
      ''
    ),
    true
  );
}

function inferSexConfidence(text, sexoCampo) {
  const allText = norm(`${text} ${sexoCampo || ''}`);
  const sexoNorm = norm(sexoCampo);

  const explicitFemale = /\bfemea\b|\bfeminha\b|\bcadela\b/.test(allText);
  const explicitMale = /\bmacho\b/.test(allText);

  const femaleSignals = [
    explicitFemale,
    /\bela\b/.test(allText),
    /\bdela\b/.test(allText),
    /\bmocinha\b/.test(allText),
    /\bmenina\b/.test(allText),
    /\bcadelinha\b/.test(allText),
    /\bcastrada\b/.test(allText),
    /\bnao castrada\b/.test(allText),
    /\bcio\b/.test(allText),
    /\bprimeiro cio\b/.test(allText),
    sexoNorm.includes('femea')
  ].filter(Boolean).length;

  const maleSignals = [
    explicitMale,
    /\bele\b/.test(allText),
    /\bdele\b/.test(allText),
    /\bmenino\b/.test(allText),
    /\bmocinho\b/.test(allText),
    /\bcastrado\b/.test(allText),
    /\bnao castrado\b/.test(allText),
    sexoNorm.includes('macho')
  ].filter(Boolean).length;

  const hasFemaleStrong =
    explicitFemale ||
    /\bela\b|\bdela\b|\bcio\b|\bprimeiro cio\b|\bcastrada\b|\bnao castrada\b/.test(allText);

  const hasMaleStrong =
    explicitMale ||
    /\bmacho\b|\bele\b|\bdele\b|\bnao castrado\b|\bcastrado\b/.test(allText);

  if (hasFemaleStrong && !explicitMale) {
    return { sexo: 'femea', confidence: 0.95, femaleSignals, maleSignals, conflict: maleSignals > 0 };
  }

  if (hasMaleStrong && !explicitFemale && femaleSignals === 0) {
    return { sexo: 'macho', confidence: 0.9, femaleSignals, maleSignals, conflict: false };
  }

  if (explicitFemale && explicitMale) {
    return { sexo: '', confidence: 0.25, femaleSignals, maleSignals, conflict: true };
  }

  if (femaleSignals > maleSignals && femaleSignals >= 2) {
    return { sexo: 'femea', confidence: 0.75, femaleSignals, maleSignals, conflict: maleSignals > 0 };
  }

  if (maleSignals > femaleSignals && maleSignals >= 2) {
    return { sexo: 'macho', confidence: 0.75, femaleSignals, maleSignals, conflict: femaleSignals > 0 };
  }

  return { sexo: '', confidence: 0.3, femaleSignals, maleSignals, conflict: femaleSignals > 0 && maleSignals > 0 };
}

function inferDogCount(text, resumo = {}) {
  const allText = norm(text);
  const nome = norm(resumo?.cao_nome || '');

  const hasTwoNamesInField =
    /\b[a-z]{2,}\s+e\s+[a-z]{2,}\b/.test(nome) &&
    !/maia\s+e\s+.*maio/.test(nome);

  const strongMultiSignals = [
    /\bduas\b/.test(allText),
    /\bdois\b/.test(allText),
    /\bas duas\b/.test(allText),
    /\bos dois\b/.test(allText),
    /\belas sao\b/.test(allText),
    /\beles sao\b/.test(allText),
    /\buma\b.*\boutra\b/.test(allText),
    /\bum\b.*\boutro\b/.test(allText),
    hasTwoNamesInField,
    /suzy.*maya|maya.*suzy/.test(allText),
    /castrada.*\b(e|,)\b.*nao castrada|nao castrada.*\b(e|,)\b.*castrada/.test(allText),
    /castrado.*\b(e|,)\b.*nao castrado|nao castrado.*\b(e|,)\b.*castrado/.test(allText)
  ].filter(Boolean).length;

  const strongSingleSignals = [
    /\buma so\b/.test(allText),
    /\bum so\b/.test(allText),
    /\bso uma\b/.test(allText),
    /\bso um\b/.test(allText),
    /\bela\b/.test(allText),
    /\bele\b/.test(allText),
    /\bminha filha\b/.test(allText),
    /\bmeu filho\b/.test(allText),
    /ela tem .* vai fazer/.test(allText),
    /ele tem .* vai fazer/.test(allText),
    /maia.*raca.*labrador.*idade.*seis.*vai fazer sete.*maio/.test(allText),
    /idade.*seis.*vai fazer sete/.test(allText)
  ].filter(Boolean).length;

  if (strongMultiSignals >= 2) return { count: 'multiple', confidence: 0.9, strongMultiSignals, strongSingleSignals };
  if (strongSingleSignals >= 2 && strongMultiSignals < 2) return { count: 'single', confidence: 0.85, strongMultiSignals, strongSingleSignals };
  if (strongMultiSignals === 1 && strongSingleSignals === 0) return { count: 'possible_multiple', confidence: 0.55, strongMultiSignals, strongSingleSignals };

  return { count: '', confidence: 0.3, strongMultiSignals, strongSingleSignals };
}

function wasAskedAboutFutureCastration(text) {
  return /pensa em castra|pretende castra|vai castra|castra-lo em breve|castra lo em breve|castr谩-lo em breve/.test(norm(text));
}

function leadRefusedFutureCastration(lastLead, lastBruna, fullText) {
  const previousAsked = wasAskedAboutFutureCastration(lastBruna) || wasAskedAboutFutureCastration(fullText);
  const leadText = norm(lastLead);
  const allText = norm(fullText);

  const explicitRefusal = /nao pretendo castra|nao vou castra|nao penso em castra|sem previsao|nao tenho previsao|nao quero castra|nao tenho interesse/.test(allText);

  const shortNoAfterQuestion =
    previousAsked &&
    /^(nao|n茫o|n|negativo|nao tenho interesse|nao pretendo)(\b|\.|!|\?|$)/.test(leadText);

  return explicitRefusal || shortNoAfterQuestion;
}

function leadWillCastrate(lastLead, lastBruna, fullText) {
  const previousAsked = wasAskedAboutFutureCastration(lastBruna) || wasAskedAboutFutureCastration(fullText);
  const leadText = norm(lastLead);
  const allText = norm(fullText);

  const explicitYes = /vou castra|pretendo castra|penso em castra|quero castra|em breve|assim que/.test(allText);

  const shortYesAfterQuestion =
    previousAsked &&
    /^(sim|s|positivo|pretendo|vou|penso)(\b|\.|!|\?|$)/.test(leadText);

  return explicitYes || shortYesAfterQuestion;
}

// ==================================================
// BASE
// ==================================================

out.resumo_lead = out.resumo_lead && typeof out.resumo_lead === 'object' ? out.resumo_lead : {};
out.resumo_interno_repasse = out.resumo_interno_repasse && typeof out.resumo_interno_repasse === 'object' ? out.resumo_interno_repasse : {};

out.status_lead = out.status_lead || '';
out.ultima_intencao = out.ultima_intencao || '';
out.evento_sistema = out.evento_sistema || '';
out.proxima_acao = out.proxima_acao || '';

out.deve_repassar_humano = Boolean(out.deve_repassar_humano);
out.deve_solicitar_pagamento = Boolean(out.deve_solicitar_pagamento);
out.deve_consultar_agenda = Boolean(out.deve_consultar_agenda);
out.deve_criar_pre_reserva = Boolean(out.deve_criar_pre_reserva);
out.deve_encerrar_conversa = Boolean(out.deve_encerrar_conversa);
out.deve_enviar_guia = Boolean(out.deve_enviar_guia);

const lastLead = getLastLeadMessage();
const lastBruna = getLastBrunaMessage();
const history = clean(item.history_for_crm || '', true);

const outputText = clean(JSON.stringify(out || {}), true);
const fullText = clean([
  history,
  lastLead,
  lastBruna,
  outputText,
  out?.resumo_lead?.observacoes,
  out?.resumo_lead?.cao_nome,
  out?.resumo_lead?.cao_raca,
  out?.resumo_lead?.cao_sexo,
  out?.resumo_lead?.cao_castrado,
  out?.resumo_lead?.cao_no_cio
].filter(Boolean).join('\n'), true);

const corrections = [];

const lastLeadNorm = norm(lastLead);
const fullNorm = norm(fullText);

const asksPrice = /(quanto|valor|preco|pre莽o|di[a谩]ria|estadia|mensal|pacote|tabela|quanto fica|quanto custa)/i.test(lastLead);
const asksInfo = /(mais informa[c莽][o玫]es|como funciona|me explica|quais regras|o que precisa|socializa[c莽][a茫]o|adapta[c莽][a茫]o|hotel|hospedagem|creche|datas?)/i.test(lastLead);
const explicitAcceptEval = /(pode mandar o pix|manda o pix|pode enviar o pix|quero seguir com a avalia[c莽][茫a]o|quero fazer a avalia[c莽][茫a]o|vamos seguir com a avalia[c莽][茫a]o|vamos fazer a avalia[c莽][茫a]o|pode agendar|quero dar continuidade|vamos prosseguir)/i.test(lastLead);

const openingTraffic = /(vim do site|vim do formul[a谩]rio|vim do anuncio|vim do an煤ncio|vim da bio|vim pelo instagram|vim do instagram|quero informa[c莽][o玫]es e agendar|gostaria de saber mais|poderia me passar mais informa[c莽][o玫]es)/i.test(lastLead);

const futureResearch = /(mais pra frente|mais para frente|futuramente|quando eu for precisar|quando formos precisar|daqui a alguns meses|quando ele estiver vacinado|quando ela estiver vacinada|s[o贸] quero entender|queria saber como funciona|ferias em|f茅rias em|s[a茫]o jo[a茫]o|viagem em)/i.test(lastLead);

const hasCio = /\bcio\b|\bprimeiro cio\b/i.test(fullNorm);

const sex = inferSexConfidence(fullText, out?.resumo_lead?.cao_sexo);
const dogCount = inferDogCount(fullText, out.resumo_lead || {});

out.sexo_inferido_crm_guard = sex.sexo || '';
out.sexo_inferido_confianca_crm_guard = sex.confidence;
out.quantidade_caes_inferida_crm_guard = dogCount.count || '';
out.quantidade_caes_confianca_crm_guard = dogCount.confidence;

// ==================================================
// 1. LEGADO FORA_DO_PERFIL
// ==================================================

if (out.ultima_intencao === 'FORA_DO_PERFIL') {
  if (/potencial de dano|pitbull|pit bull|rottweiler|american bully|akita|chow chow|doberman|fila brasileiro|dogo argentino/i.test(fullText)) {
    out.ultima_intencao = 'RACA_POTENCIAL_DANO';
    out.status_lead = 'ENCERRADO_NAO_PERFIL';
    out.evento_sistema = 'CONVERSA_ENCERRADA';
    out.deve_encerrar_conversa = true;
    out.deve_repassar_humano = false;
    out.deve_solicitar_pagamento = false;
    out.deve_consultar_agenda = false;
    out.deve_criar_pre_reserva = false;
    corrections.push('fora_do_perfil_convertido_para_raca_potencial_dano');
  } else if (/macho|nao castrado|n茫o castrado/i.test(fullText) && sex.sexo === 'macho') {
    out.ultima_intencao = 'MACHO_NAO_CASTRADO';
    corrections.push('fora_do_perfil_convertido_para_macho_nao_castrado');
  } else {
    out.ultima_intencao = 'INFORMOU_DADOS_CAO';
    out.status_lead = out.status_lead === 'ENCERRADO_NAO_PERFIL' ? 'QUALIFICANDO' : out.status_lead;
    out.evento_sistema = out.evento_sistema === 'CONVERSA_ENCERRADA' ? '' : out.evento_sistema;
    out.deve_encerrar_conversa = false;
    corrections.push('fora_do_perfil_generico_removido');
  }
}

// ==================================================
// 2. PRE脟O, INFORMA脟脙O, ABERTURA E PESQUISA FUTURA
// ==================================================

if ((asksPrice || asksInfo || openingTraffic || futureResearch) && !explicitAcceptEval) {
  if (asksPrice) out.ultima_intencao = 'PEDIU_VALOR';
  else if (openingTraffic) out.ultima_intencao = /hotel|hospedagem/i.test(lastLead) ? 'INTERESSE_HOTEL' : 'INTERESSE_CRECHE';

  out.status_lead = openingTraffic ? 'COLETANDO_DADOS' : 'QUALIFICANDO';

  if (out.evento_sistema === 'PIX_SOLICITADO') out.evento_sistema = '';
  if (openingTraffic && !out.evento_sistema) out.evento_sistema = 'FORMULARIO_RECEBIDO';

  out.deve_solicitar_pagamento = false;
  out.deve_consultar_agenda = false;
  out.deve_criar_pre_reserva = false;
  out.deve_encerrar_conversa = false;

  if (/pagamento|pix|comprovante|taxa/i.test(String(out.proxima_acao || ''))) {
    out.proxima_acao = futureResearch
      ? 'responder pesquisa futura e criar urgencia saudavel sem cobrar pagamento'
      : 'responder d煤vida e seguir qualifica莽茫o com suavidade';
  }

  corrections.push(
    futureResearch
      ? 'pesquisa_futura_bloqueou_pagamento'
      : openingTraffic
        ? 'abertura_trafego_bloqueou_pagamento'
        : 'ultima_mensagem_indica_duvida_de_valor_ou_info'
  );
}

// ==================================================
// 3. F脢MEA, CIO E FALSO MACHO N脙O CASTRADO
// ==================================================

if (sex.sexo === 'femea' && sex.confidence >= 0.75) {
  out.resumo_lead.cao_sexo = out.resumo_lead.cao_sexo || 'femea';

  if (out.ultima_intencao === 'MACHO_NAO_CASTRADO') {
    out.ultima_intencao = 'INFORMOU_DADOS_CAO';
    out.status_lead = out.status_lead === 'ENCERRADO_NAO_PERFIL' ? 'QUALIFICANDO' : out.status_lead;
    out.evento_sistema = out.evento_sistema === 'CONVERSA_ENCERRADA' ? '' : out.evento_sistema;
    out.deve_encerrar_conversa = false;
    out.deve_repassar_humano = false;
    out.deve_solicitar_pagamento = false;
    out.deve_consultar_agenda = false;
    out.deve_criar_pre_reserva = false;

    out.resumo_lead.observacoes = appendObs(
      out.resumo_lead.observacoes,
      'Guard CRM bloqueou MACHO_NAO_CASTRADO porque o contexto indica f锚mea.'
    );

    corrections.push('corrigido_falso_macho_nao_castrado');
  }
}

if (hasCio) {
  out.resumo_lead.cao_no_cio = 'sim';

  if (out.status_lead === 'ENCERRADO_NAO_PERFIL' && out.ultima_intencao !== 'RACA_POTENCIAL_DANO') {
    out.status_lead = 'QUALIFICANDO';
    out.ultima_intencao = 'INFORMOU_DADOS_CAO';
    out.evento_sistema = '';
    out.deve_encerrar_conversa = false;
    out.deve_repassar_humano = false;
    out.deve_solicitar_pagamento = false;
    out.deve_consultar_agenda = false;
    out.deve_criar_pre_reserva = false;

    corrections.push('corrigido_encerramento_por_femea_no_cio');
  }

  out.resumo_lead.observacoes = appendObs(
    out.resumo_lead.observacoes,
    'F锚mea no cio: atendimento pode seguir, mas frequ锚ncia/adapta莽茫o/hotel devem ocorrer fora do per铆odo de cio.'
  );
}

// ==================================================
// 4. UM C脙O VS M脷LTIPLOS C脙ES
// ==================================================

if (
  dogCount.count === 'single' &&
  (
    out.motivo_repasse === 'caso_ambiguo_multiplos_caes' ||
    /dois caes|duas cadelinhas|mais de um c茫o|mais de um cao|sao dois|s茫o dois/i.test(outputText)
  )
) {
  out.status_lead = 'QUALIFICANDO';
  out.ultima_intencao = 'INFORMOU_DADOS_CAO';
  out.evento_sistema = '';
  out.deve_repassar_humano = false;
  out.motivo_repasse = '';
  out.deve_encerrar_conversa = false;

  out.resumo_lead.observacoes = appendObs(
    out.resumo_lead.observacoes,
    'Guard CRM bloqueou hip贸tese de m煤ltiplos c茫es porque o contexto indica um 煤nico c茫o.'
  );

  corrections.push('corrigido_falso_multiplos_caes');
}

// ==================================================
// 5. MACHO N脙O CASTRADO EM 2 ETAPAS
// ==================================================

const idadeAnos = parseAgeYears(
  pick(out?.resumo_lead?.cao_idade_anos, item?.inputs?.idade_cao_anos, item?.inputs?.cao_idade_anos),
  pick(out?.resumo_lead?.cao_idade_texto, lastLead, history)
);

const castrado = pick(out?.resumo_lead?.cao_castrado, item?.inputs?.cao_castrado);

const machoAltaConfianca =
  sex.sexo === 'macho' &&
  sex.confidence >= 0.75 &&
  sex.femaleSignals === 0;

const machoNaoCastradoDetectado =
  machoAltaConfianca &&
  idadeAnos !== null &&
  idadeAnos >= 0.6667 &&
  isFalseLike(castrado);

if (machoNaoCastradoDetectado) {
  const recusouCastracao = leadRefusedFutureCastration(lastLead, lastBruna, fullText);
  const vaiCastrar = leadWillCastrate(lastLead, lastBruna, fullText);

  out.ultima_intencao = 'MACHO_NAO_CASTRADO';
  out.resumo_lead.cao_sexo = 'macho';
  out.resumo_lead.cao_castrado = 'nao';

  out.deve_repassar_humano = false;
  out.motivo_repasse = '';
  out.deve_solicitar_pagamento = false;
  out.deve_consultar_agenda = false;
  out.deve_criar_pre_reserva = false;

  if (recusouCastracao) {
    out.status_lead = 'ENCERRADO_NAO_PERFIL';
    out.evento_sistema = 'CONVERSA_ENCERRADA';
    out.deve_encerrar_conversa = true;
    out.resumo_lead.observacoes = appendObs(out.resumo_lead.observacoes, 'Encerrado por MACHO_NAO_CASTRADO sem previs茫o de castra莽茫o.');
    corrections.push('macho_nao_castrado_encerrado_sem_previsao');
  } else if (vaiCastrar) {
    out.status_lead = 'PRE_REPROVADO';
    out.evento_sistema = '';
    out.deve_encerrar_conversa = false;
    out.resumo_lead.observacoes = appendObs(out.resumo_lead.observacoes, 'Macho n茫o castrado. Tutor sinalizou inten莽茫o de castrar futuramente.');
    corrections.push('macho_nao_castrado_vai_castrar');
  } else {
    out.status_lead = 'PRE_REPROVADO';
    out.evento_sistema = '';
    out.deve_encerrar_conversa = false;
    out.resumo_lead.observacoes = appendObs(out.resumo_lead.observacoes, 'Macho n茫o castrado com 8 meses ou mais. Aguardando tutor dizer se pretende castrar em breve.');
    corrections.push('macho_nao_castrado_primeira_etapa');
  }
}

// Se o CRM saiu com MACHO_NAO_CASTRADO, mas n茫o h谩 confian莽a suficiente, volta para qualifica莽茫o.
if (
  out.ultima_intencao === 'MACHO_NAO_CASTRADO' &&
  (!machoAltaConfianca || sex.conflict || sex.confidence < 0.75)
) {
  out.status_lead = 'QUALIFICANDO';
  out.ultima_intencao = 'INFORMOU_DADOS_CAO';
  out.evento_sistema = '';
  out.deve_repassar_humano = false;
  out.motivo_repasse = '';
  out.deve_solicitar_pagamento = false;
  out.deve_consultar_agenda = false;
  out.deve_criar_pre_reserva = false;
  out.deve_encerrar_conversa = false;

  out.resumo_lead.observacoes = appendObs(
    out.resumo_lead.observacoes,
    'Guard CRM bloqueou MACHO_NAO_CASTRADO por baixa confian莽a em sexo/idade/castra莽茫o.'
  );

  corrections.push('bloqueado_macho_nao_castrado_baixa_confianca');
}

// ==================================================
// 6. AGENDA SEM COMPROVANTE
// ==================================================

const statusPagamento = norm(pick(out.status_pagamento, item.inputs?.status_pagamento));

const comprovanteRecebido =
  bool(out.comprovante_recebido) ||
  bool(out?.resumo_lead?.comprovante_recebido) ||
  bool(item.inputs?.comprovante_recebido) ||
  bool(item.inputs?.resumo_lead?.comprovante_recebido) ||
  ['comprovante_recebido', 'validacao_humana_pendente', 'aprovado_humano'].includes(statusPagamento);

const tentouAgendaSemComprovante =
  !comprovanteRecebido &&
  (
    out.status_lead === 'AGUARDANDO_ESCOLHA_HORARIO' ||
    out.status_lead === 'PRE_RESERVA_CRIADA' ||
    out.evento_sistema === 'AGENDA_CONSULTADA' ||
    out.evento_sistema === 'HORARIOS_ENVIADOS' ||
    out.evento_sistema === 'PRE_RESERVA_CRIADA' ||
    out.deve_consultar_agenda === true ||
    out.deve_criar_pre_reserva === true
  );

if (tentouAgendaSemComprovante) {
  out.status_lead = 'AGUARDANDO_PAGAMENTO';
  out.evento_sistema = 'PIX_SOLICITADO';
  out.deve_solicitar_pagamento = true;
  out.deve_consultar_agenda = false;
  out.deve_criar_pre_reserva = false;
  out.deve_encerrar_conversa = false;

  out.resumo_lead.comprovante_recebido = false;
  out.resumo_lead.data_hora_pre_reserva = null;
  out.resumo_lead.observacoes = appendObs(out.resumo_lead.observacoes, 'Agenda bloqueada por aus锚ncia de comprovante recebido.');

  corrections.push('agenda_bloqueada_sem_comprovante');
}

// ==================================================
// 7. FINALIZA
// ==================================================

item.output = out;
item.guard_crm_reason = corrections.join('|') || '';
item.guard_crm_debug = {
  applied: corrections.length > 0,
  corrections,
  last_lead_message: lastLead,
  last_bruna_message: lastBruna,
  asks_price: asksPrice,
  asks_info: asksInfo,
  opening_traffic: openingTraffic,
  future_research: futureResearch,
  explicit_accept_eval: explicitAcceptEval,
  sex,
  dogCount,
  idadeAnos,
  comprovanteRecebido
};

return [{ json: item }];

